arguments.file_text:
@using sv_c30c6691d2504d05b26e72b1b11e58fa.Services

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

@using sv_c30c6691d2504d05b26e72b1b11e58fa.Services

<div class="message-list" @onscroll="HandleScroll" @ref="_scrollContainer">
    @if (_loadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ReplyCount="GetReplyCount(message.Id)"
                     OnOpenThread="() => OnOpenThread.InvokeAsync(message)"
                     OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }

    private ElementReference _scrollContainer;
    private bool _loadingMore;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.GetValueOrDefault(messageId);

    private async Task HandleScroll()
    {
        if (!HasMoreMessages || _loadingMore) return;

        // Trigger load-more when scrolled near top
        _loadingMore = true;
        await OnLoadMore.InvokeAsync();
        _loadingMore = false;
    }
}

@using sv_c30c6691d2504d05b26e72b1b11e58fa.Services

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="channel-header">
            <h2># @Channel.Name</h2>
            <p class="channel-description">@Channel.Description</p>
        </div>

        <MessageList Messages="Messages"
                     ThreadReplyCounts="ThreadReplyCounts"
                     HasMoreMessages="HasMoreMessages"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact"
                     OnLoadMore="OnLoadMore" />

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
}

@using sv_c30c6691d2504d05b26e72b1b11e58fa.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="message-header">
                <span class="message-author">@RootMessage.Author</span>
                <span class="message-time">@FormatRelativeTime(RootMessage.SentAt)</span>
            </div>
            <div class="message-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var reply in ThreadMessages)
            {
                <MessageItem Message="reply"
                             ReplyCount="0"
                             OnReact="(emoji) => OnReact.InvokeAsync((reply.Id, emoji))" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSubmit="OnReply" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

