arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@using sv_c30c6691d2504d05b26e72b1b11e58fa.Components.Chat
@using sv_c30c6691d2504d05b26e72b1b11e58fa.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannel?.Id ?? 0"
                    OnChannelSelected="SelectChannel" />

    <div class="main-panel @(_threadOpen ? "with-thread" : "")">
        <MessageArea Channel="_activeChannel"
                     Messages="_messages"
                     ThreadReplyCounts="_threadReplyCounts"
                     HasMoreMessages="_hasMoreMessages"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnLoadMore="LoadMoreMessages"
                     OnSendMessage="SendMessage" />
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     ThreadMessages="_threadMessages"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply"
                     OnReact="HandleReaction" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _threadReplyCounts = [];
    private bool _hasMoreMessages = true;
    private const int PageSize = 30;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        _activeChannel = channel;
        _messages = [];
        _hasMoreMessages = true;
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];

        await LoadMessages();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Update the unread count locally
        var idx = _channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            _channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task LoadMessages()
    {
        if (_activeChannel is null) return;

        var batch = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);
        if (batch.Count < PageSize) _hasMoreMessages = false;

        _messages.InsertRange(0, batch);
        await BuildThreadReplyCounts();
    }

    private async Task LoadMoreMessages()
    {
        await LoadMessages();
    }

    private async Task BuildThreadReplyCounts()
    {
        // Count replies: messages with a ReplyToId pointing to another message in the list
        _threadReplyCounts = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());

        await Task.CompletedTask;
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannel.Id, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannel is null || _threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            _activeChannel.Id, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);
        _messages.Add(reply);

        // Update reply count
        _threadReplyCounts[_threadRootMessage.Id] =
            _threadReplyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the reaction in the local message list
        UpdateReactionInList(_messages, args.MessageId, args.Emoji);
        UpdateReactionInList(_threadMessages, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionInList(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FindIndex(r => r.Emoji == emoji);

        if (existing >= 0)
        {
            var r = reactions[existing];
            reactions[existing] = r with { Users = [..r.Users, "You"] };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }

        messages[idx] = msg with { Reactions = reactions };
    }
}

/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ===== Channel Sidebar ===== */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

::deep .sidebar-title {
    padding: 16px;
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
    border-bottom: 1px solid #202225;
}

::deep .channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 8px;
    transition: background 0.15s;
}

::deep .channel-item:hover {
    background: #36393f;
}

::deep .channel-item.active {
    background: #393c43;
    color: #fff;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
}

::deep .channel-desc {
    width: 100%;
    font-size: 0.75rem;
    color: #72767d;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ===== Main Panel ===== */
.main-panel {
    flex: 1;
    display: flex;
    min-width: 0;
}

.main-panel.with-thread {
    flex: 0 0 55%;
}

::deep .message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
}

::deep .channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #202225;
    background: #36393f;
}

::deep .channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

::deep .channel-description {
    margin: 4px 0 0;
    font-size: 0.8rem;
    color: #8e9297;
}

::deep .no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

/* ===== Message List ===== */
::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
}

::deep .loading-indicator {
    text-align: center;
    padding: 12px;
    color: #72767d;
    font-size: 0.85rem;
}

/* ===== Message Item ===== */
::deep .message-item {
    position: relative;
    padding: 8px 12px;
    border-radius: 4px;
    margin-bottom: 4px;
    transition: background 0.1s;
}

::deep .message-item:hover {
    background: #32353b;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 4px;
}

::deep .message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

::deep .message-time {
    font-size: 0.75rem;
    color: #72767d;
}

::deep .message-content {
    font-size: 0.9rem;
    line-height: 1.4;
    word-wrap: break-word;
}

/* ===== Reactions ===== */
::deep .reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

::deep .reaction-badge {
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 2px 8px;
    font-size: 0.8rem;
    color: #dcddde;
    cursor: pointer;
    transition: background 0.15s;
}

::deep .reaction-badge:hover {
    background: #3c3f45;
    border-color: #72767d;
}

/* ===== Thread Link ===== */
::deep .thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 4px;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* ===== Message Actions (hover) ===== */
::deep .message-actions {
    position: absolute;
    top: -8px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.3);
}

::deep .action-btn {
    background: none;
    border: none;
    font-size: 1rem;
    padding: 4px 6px;
    cursor: pointer;
    border-radius: 3px;
    transition: background 0.1s;
}

::deep .action-btn:hover {
    background: #36393f;
}

/* ===== Emoji Picker ===== */
::deep .emoji-picker {
    position: absolute;
    top: -8px;
    right: 80px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.3);
    z-index: 10;
}

::deep .emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 4px;
    cursor: pointer;
    border-radius: 3px;
    transition: background 0.1s;
}

::deep .emoji-option:hover {
    background: #36393f;
}

/* ===== Message Input ===== */
::deep .message-input {
    padding: 12px 20px;
    border-top: 1px solid #202225;
    display: flex;
    gap: 8px;
    align-items: flex-end;
    background: #36393f;
}

::deep .message-input textarea {
