    border: none;
    border-radius: 8px;
    padding: 10px 14px;
    color: #dcddde;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
}

::deep .message-input textarea::placeholder {
    color: #72767d;
}

::deep .message-input textarea:focus {
    box-shadow: 0 0 0 1px #5865f2;
}

::deep .btn-send {
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    white-space: nowrap;
    transition: background 0.15s;
}

::deep .btn-send:hover:not(:disabled) {
    background: #4752c4;
}

::deep .btn-send:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ===== Thread Panel ===== */
::deep .thread-panel {
    width: 25%;
    min-width: 280px;
    background: #2f3136;
    color: #dcddde;
    border-left: 1px solid #202225;
    display: flex;
    flex-direction: column;
}

::deep .thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
}

::deep .thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
}

::deep .close-btn {
