@page "/chat"
@rendermode InteractiveServer
@using sv_c30c6691d2504d05b26e72b1b11e58fa.Components.Chat
@using sv_c30c6691d2504d05b26e72b1b11e58fa.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannel?.Id ?? 0"
                    OnChannelSelected="SelectChannel" />

    <div class="main-panel @(_threadOpen ? "with-thread" : "")">
        <MessageArea Channel="_activeChannel"
                     Messages="_messages"
                     ThreadReplyCounts="_threadReplyCounts"
                     HasMoreMessages="_hasMoreMessages"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnLoadMore="LoadMoreMessages"
                     OnSendMessage="SendMessage" />
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     ThreadMessages="_threadMessages"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply"
                     OnReact="HandleReaction" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _threadReplyCounts = [];
    private bool _hasMoreMessages = true;
    private const int PageSize = 30;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        _activeChannel = channel;
        _messages = [];
        _hasMoreMessages = true;
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];

        await LoadMessages();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Update the unread count locally
        var idx = _channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            _channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task LoadMessages()
    {
        if (_activeChannel is null) return;

        var batch = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);
        if (batch.Count < PageSize) _hasMoreMessages = false;

        _messages.InsertRange(0, batch);
        await BuildThreadReplyCounts();
    }

    private async Task LoadMoreMessages()
    {
        await LoadMessages();
    }

    private async Task BuildThreadReplyCounts()
    {
        // Count replies: messages with a ReplyToId pointing to another message in the list
        _threadReplyCounts = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());

        await Task.CompletedTask;
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannel.Id, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannel is null || _threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            _activeChannel.Id, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);
        _messages.Add(reply);

        // Update reply count
        _threadReplyCounts[_threadRootMessage.Id] =
            _threadReplyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the reaction in the local message list
        UpdateReactionInList(_messages, args.MessageId, args.Emoji);
        UpdateReactionInList(_threadMessages, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionInList(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FindIndex(r => r.Emoji == emoji);

        if (existing >= 0)
        {
            var r = reactions[existing];
            reactions[existing] = r with { Users = [..r.Users, "You"] };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }

        messages[idx] = msg with { Reactions = reactions };
    }
}

