toolArgs.file_text:
/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ===== Channel Sidebar ===== */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #202225;
}

::deep .sidebar-title {
    padding: 16px;
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
    border-bottom: 1px solid #202225;
}

::deep .channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 8px;
    transition: background 0.15s;
}

::deep .channel-item:hover {
    background: #36393f;
}

::deep .channel-item.active {
    background: #393c43;
    color: #fff;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
}

::deep .channel-desc {
    width: 100%;
    font-size: 0.75rem;
    color: #72767d;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ===== Main Panel ===== */
.main-panel {
    flex: 1;
    display: flex;
    min-width: 0;
}

.main-panel.with-thread {
    flex: 0 0 55%;
}

::deep .message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
}

::deep .channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #202225;
    background: #36393f;
}

::deep .channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

::deep .channel-description {
    margin: 4px 0 0;
    font-size: 0.8rem;
    color: #8e9297;
}

::deep .no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #72767d;
    font-size: 1.1rem;
}

/* ===== Message List ===== */
::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
}

::deep .loading-indicator {
    text-align: center;
    padding: 12px;
    color: #72767d;
    font-size: 0.85rem;
}

/* ===== Message Item ===== */
::deep .message-item {
    position: relative;
    padding: 8px 12px;
    border-radius: 4px;
    margin-bottom: 4px;
    transition: background 0.1s;
}

::deep .message-item:hover {
    background: #32353b;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 4px;
}

::deep .message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

::deep .message-time {
    font-size: 0.75rem;
    color: #72767d;
}

::deep .message-content {
    font-size: 0.9rem;
    line-height: 1.4;
    word-wrap: break-word;
}

/* ===== Reactions ===== */
::deep .reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

